import { CommonModule } from '@angular/common';
import { Component, computed, Inject, inject } from '@angular/core';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { MatFormFieldModule, MatLabel } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import { MatSlideToggleModule } from '@angular/material/slide-toggle';
import { MatSnackBarModule } from '@angular/material/snack-bar';
import { LoaderComponent } from '../../shared/loader/loader.component';
import { LoaderService } from '../../shared/loader/loader.service';
import { allowOnlyLetters, trimInput } from '../../pages/master/master.utils';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { CargoService } from '../../pages/master/cargo/cargo.service';
import { SnackbarService } from '../../shared/snack-bar/snack-bar.service';
import { allowLimitedInput } from '../../pages/master/master.utils';
import { handlePasteText } from '../../pages/master/master.utils';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';

@Component({
  selector: 'app-create-cargo',
  standalone: true,
  imports: [MatFormFieldModule,
    MatLabel, MatIconModule, MatInputModule, ReactiveFormsModule, CommonModule, MatSlideToggleModule, MatSnackBarModule, LoaderComponent, MatProgressSpinnerModule],
  templateUrl: './create-cargo.component.html',
  styleUrl: './create-cargo.component.css'
})
export class CreateCargoComponent {
  private loader = inject(LoaderService);
  isLoading = computed(() => this.loader.dialogLoading());

  disallowNumericData = allowOnlyLetters;
  allowLimitedInput = allowLimitedInput;
  cargoForm: FormGroup;
  isEditMode = false;
  constructor(
    private fb: FormBuilder,
    private dialogRef: MatDialogRef<CreateCargoComponent>,
    @Inject(MAT_DIALOG_DATA) public existingdata: any,
    private cargoService: CargoService,
    private snackBar: SnackbarService
  ) {
    const data = existingdata?.rowData;
    this.isEditMode = !!data;
    this.cargoForm = this.fb.group({
      cargo_id: [data?.cargo_id || 0],
      type: [data?.type || '', Validators.required],
    });
  }
  //method to trim the input
  onInputTrim(controlName: string): void {
    const control = this.cargoForm.get(controlName);
    trimInput(control);
  }


  onPaste(event: ClipboardEvent): void {
    const value = handlePasteText(event);
    this.cargoForm.get('type')?.setValue(value);
  }

  // onSubmit method will trigger when the Add or Edit cargo button clicks
  onSubmit() {
    if (this.cargoForm.valid) {
      this.loader.showDialogLoader();
      this.cargoService.CargoDataToDB(this.cargoForm.value).subscribe({
        next: (res) => {
          this.loader.hideDialogLoader();
          this.snackBar.showSuccess(res.message);
          this.dialogRef.close("refresh");
        },
        error: (error) => {
          this.loader.hideDialogLoader();
          const errorMsg = error.error?.error || 'Something went wrong. Please try again.';
          this.snackBar.showError(errorMsg);
        }
      })
    }
  }


  closeDialog() {
    this.dialogRef.close();
  }
}
